parameters.jsCode:
// Standardize resume data for AI analysis
// Since this workflow processes manually uploaded resumes,
// job details need to be configured or passed with the file

const input = $input.first().json;
const fileName = $('OneDrive Trigger').first().json.name || 'Unknown';

// Extract text from PDF extraction
const resumeText = input.text || '';

return [{
  json: {
    // Resume data
    candidateResume: resumeText,
    fileName: fileName,
    candidateName: 'Extract from resume',
    candidateEmail: 'Extract from resume',

    // Job details - CONFIGURE THESE for each position
    // These can be updated manually or passed from a job lookup
    jobTitle: 'Position Title - CONFIGURE',
    jobDepartment: 'Department - CONFIGURE',
    jobLocation: 'Location - CONFIGURE',
    jobPayRange: 'Pay Range - CONFIGURE',
    jobRemoteStatus: 'Remote/Hybrid/Onsite - CONFIGURE',
    jobDescription: 'Full job description text - CONFIGURE',

    // File metadata
    driveLink: $('OneDrive Trigger').first().json.webUrl || '',
    processedAt: new Date().toISOString()
  }
}];

// Prepare data for Google Sheets logging
const candidateInfo = $('Extract Candidate Info').first().json;
const aiAnalysis = $('AI Recruiter Analysis').first().json;
const resumeData = $('Standardize Resume Data').first().json;

return [{
  json: {
    ...candidateInfo,
    aiAnalysis: aiAnalysis,
    resumeData: resumeData,
    readyForSheet: true
  }
}];

